-- owner_id = 1: usuario admin semilla de auth-service (ver ADR-0004).
INSERT INTO product (id, title, description, address, room_number, number_of_bathrooms, category_id, city_id, owner_id) VALUES
-- La Guajira -----------------------------------------------------------------
(1, 'Apartamento con vista al mar en el Malecón', 'Apartamento fresco con balcón sobre el mar Caribe, a pasos del Malecón de Riohacha y del muelle turístico. Ideal como base para conocer el Santuario de los Flamencos y el Cabo de la Vela.', 'Malecón, Riohacha', 2, 1, 1, 1, 1),
(2, 'Casa fresca a cuadras de la playa', 'Casa amplia de un piso con patio sombreado y hamacas, a pocas cuadras de la playa de Riohacha y del mercado nuevo. Perfecta para familias.', 'Barrio El Centro, Riohacha', 3, 2, 2, 1, 1),
(3, 'Cabaña ecológica en la vía a Camarones', 'Cabaña rodeada de trupillos en la vía al Santuario de Fauna y Flora Los Flamencos. Amaneceres con flamencos rosados a 10 minutos.', 'Vía a Camarones, Riohacha', 2, 1, 3, 1, 1),
(4, 'Cabaña frente al mar en Palomino', 'Cabaña de madera y palma a pasos de la playa de Palomino, donde la Sierra Nevada se encuentra con el Caribe. Atardeceres inolvidables desde la hamaca.', 'Playa de Palomino', 2, 1, 3, 2, 1),
(5, 'Casa entre el río y el mar', 'Casa tropical a mitad de camino entre el río Palomino y la playa — podés hacer tubing en el río por la mañana y ver el atardecer en el mar.', 'Km 1 vía al río, Palomino', 3, 2, 2, 2, 1),
(6, 'Casa con jardín tropical y hamacas', 'Casa estilo hostal con jardín lleno de palmas, zona de hamacas y cocina abierta. El plan perfecto para desconectarse en Palomino.', 'Calle principal, Palomino', 4, 3, 2, 2, 1),
(7, 'Ranchería wayuu con vista al mar', 'Alojamiento tradicional wayuu con chinchorros y comida típica, frente al mar turquesa del Cabo de la Vela. Una experiencia auténtica de la Alta Guajira.', 'Cabo de la Vela', 2, 1, 3, 3, 1),
(8, 'Cabaña frente al Pilón de Azúcar', 'Cabaña sencilla con vista directa al Pilón de Azúcar y al mar. Kitesurf, playa ojo de agua y cielos estrellados sin contaminación lumínica.', 'Vía al Pilón, Cabo de la Vela', 1, 1, 3, 3, 1),
(9, 'Casa de sal frente a las salinas', 'Casa fresca frente a las salinas de Manaure, con sus montañas de sal blanca y charcas rosadas. Un paisaje único en Colombia.', 'Frente a las salinas, Manaure', 3, 2, 2, 4, 1),
(10, 'Cabaña wayuu cerca a las charcas rosadas', 'Cabaña tradicional con chinchorros, atendida por una familia wayuu, a minutos de las charcas rosadas de las salinas de Manaure.', 'Vereda Shiruria, Manaure', 2, 1, 3, 4, 1),
(11, 'Casa del desierto, base para Punta Gallinas', 'Casa de material en el casco urbano de Uribia, la capital indígena de Colombia — el punto de partida ideal para expediciones a Punta Gallinas y Bahía Hondita.', 'Centro, Uribia', 3, 2, 2, 5, 1),
(12, 'Ranchería tradicional en la Alta Guajira', 'Ranchería con enramada y chinchorros en pleno desierto guajiro. Noches de historias wayuu alrededor del fogón.', 'Vía a Punta Gallinas, Uribia', 2, 1, 3, 5, 1),
(13, 'Casa de playa en Dibulla', 'Casa frente al mar en Dibulla, con vista a la Sierra Nevada nevada al amanecer. Playas solas, pescado fresco y tranquilidad total.', 'Playa de Dibulla', 3, 2, 2, 6, 1),
(14, 'Finca entre el mar y la Sierra Nevada', 'Finca productiva con frutales tropicales entre la playa y las estribaciones de la Sierra Nevada de Santa Marta. Río propio y cacao de la región.', 'Vereda Mingueo, Dibulla', 4, 3, 4, 6, 1),
-- Cesar ----------------------------------------------------------------------
(15, 'Apartamento moderno cerca a la Plaza Alfonso López', 'Apartamento nuevo a cuadras de la Plaza Alfonso López, el corazón del vallenato. A pasos de restaurantes, la catedral y la casa de los Maestre.', 'Centro, Valledupar', 2, 1, 1, 7, 1),
(16, 'Casa vallenata cerca al río Guatapurí', 'Casa amplia de un piso, típica del Valle de Upar, a pocas cuadras del balneario Hurtado y la sirena del río Guatapurí. Patio con palo de mango.', 'Barrio Novalito, Valledupar', 3, 2, 2, 7, 1),
(17, 'Apartamento con piscina en el norte', 'Apartamento en conjunto cerrado con piscina y gimnasio, en la zona norte de Valledupar. Aire acondicionado en todas las habitaciones.', 'Sabanas del Valle, Valledupar', 2, 2, 1, 7, 1),
(18, 'Finca ganadera con jagüey natural', 'Finca tradicional del Cesar con potreros, arboleda nativa y un jagüey acondicionado como piscina natural. Cabalgatas y ordeño al amanecer.', 'Vía a Codazzi, Valledupar', 4, 3, 4, 7, 1),
(19, 'Casa del barrio Cañaguate', 'Casa familiar en el barrio que le da nombre al árbol insignia de la ciudad — en enero florece amarillo entero. Cerca al parque de la Leyenda Vallenata.', 'Barrio Cañaguate, Valledupar', 3, 2, 2, 7, 1),
(20, 'Cabaña de montaña en Pueblo Bello', 'Cabaña con chimenea en el clima frío de Pueblo Bello, la puerta de entrada a la Sierra Nevada. Neblina, café y silencio.', 'Vía a Nabusímake, Pueblo Bello', 2, 1, 3, 8, 1),
(21, 'Finca cafetera con vista a la Sierra', 'Finca cafetera en las faldas de la Sierra Nevada, con recorridos por los cultivos y café tostado en casa. Comunidad arhuaca vecina.', 'Vereda Las Mercedes, Pueblo Bello', 3, 2, 4, 8, 1),
(22, 'Casa campestre a la entrada de la Sierra', 'Casa campestre con jardín de heliconias y vista a las montañas. El punto de partida para caminatas a Nabusímake, capital espiritual arhuaca.', 'Casco urbano, Pueblo Bello', 3, 2, 2, 8, 1),
(23, 'Casa tradicional en La Paz', 'Casa de pueblo con techos altos y mecedoras en el corredor, en La Paz — tierra de acordeoneros, a 20 minutos de Valledupar.', 'Centro, La Paz', 3, 2, 2, 9, 1),
(24, 'Finca con frutales en San Diego', 'Finca con cultivos de mango, guanábana y cítricos en el valle de San Diego. Piscina, kiosco con hamacas y noches de cielo despejado.', 'Vía Media Luna, San Diego', 4, 2, 4, 10, 1),
(25, 'Casa de descanso en San Diego', 'Casa tranquila con patio grande y árboles frutales en el pueblo de San Diego, famoso por sus parrandas vallenatas de diciembre.', 'Centro, San Diego', 3, 2, 2, 10, 1),
(26, 'Cabaña con clima de montaña', 'Cabaña en Manaure Balcón del Cesar, el pueblo con el mejor clima del departamento — 1.300 msnm de frescura en plena serranía del Perijá.', 'Vía al mirador, Manaure Balcón del Cesar', 2, 1, 3, 11, 1),
(27, 'Casa mirador del Balcón del Cesar', 'Casa con terraza-mirador sobre el valle del Cesar. Al amanecer se ve el valle entero y al fondo la Sierra Nevada.', 'Alto de la Virgen, Manaure Balcón del Cesar', 3, 2, 2, 11, 1),
(28, 'Casa frente a la Ciénaga de Zapatosa', 'Casa a la orilla de la ciénaga más grande de Colombia. Paseos en canoa, pesca artesanal y atardeceres sobre el agua en Chimichagua.', 'Malecón, Chimichagua', 3, 2, 2, 12, 1);

